// Quick search function for fallback - optimized with multiple match strategies
export const searchInternationalDrugs = (query: string): InternationalDrug[] => {
    const lowerQuery = query.toLowerCase().trim();
    if (lowerQuery.length < 2) return [];

    // Exact match first, then starts-with, then contains
    const exactMatches = internationalDrugs.filter(drug =>
        drug.name.toLowerCase() === lowerQuery ||
        drug.genericName?.toLowerCase() === lowerQuery
    );

    const startsWithMatches = internationalDrugs.filter(drug =>
        (drug.name.toLowerCase().startsWith(lowerQuery) ||
        drug.genericName?.toLowerCase().startsWith(lowerQuery)) &&
        !exactMatches.includes(drug)
    );

    const containsMatches = internationalDrugs.filter(drug =>
        (drug.name.toLowerCase().includes(lowerQuery) ||
        drug.genericName?.toLowerCase().includes(lowerQuery) ||
        drug.commonUses.toLowerCase().includes(lowerQuery) ||
        drug.category.toLowerCase().includes(lowerQuery)) &&
        !exactMatches.includes(drug) &&
        !startsWithMatches.includes(drug)
    );

    return [...exactMatches, ...startsWithMatches, ...containsMatches];
};
